***xml配置文件***

![](https://img2020.cnblogs.com/blog/2090080/202110/2090080-20211030173525069-770777167.png)


```java
<?xml version="1.0" encoding="UTF-8"?>
<beans xmlns="http://www.springframework.org/schema/beans"
       xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
       xsi:schemaLocation="http://www.springframework.org/schema/beans
        http://www.springframework.org/schema/beans/spring-beans.xsd">
    <bean id="Address" class="com.kuang.pojo.Address">
        <property name="address" value="石家庄"></property>
    </bean>
    <bean id="Student" class="com.kuang.pojo.Student">
        <!-- 第一种：普通值注入 -->
        <property name="name" value="杨传伟"></property>
        <!-- 第二种：ref注入 -->
        <property name="address" ref="Address"></property>
        <!-- 第三种：数组注入 -->
        <property name="books">
            <array>
                <value>《红楼梦》</value>
                <value>《西游记》</value>
                <value>《水浒传》</value>
                <value>《三国演义》</value>
            </array>
        </property>
        <!-- 第四种：List注入 -->
        <property name="hobbies">
            <list>
                <value>听音乐</value>
                <value>看电影</value>
                <value>敲代码</value>
                <value>摄影</value>
            </list>
        </property>

        <!-- 第五种：Map注入 -->

        <property name="card">
            <map>
                <entry key="IDcard" value="1234567"></entry>
                <entry key="STcard" value="7654321"></entry>
            </map>
        </property>
        <!-- 第六种：Set注入 -->
        <property name="games">
            <set>
                <value>跑跑卡丁车官方竞速版</value>
                <value>王者荣耀</value>
            </set>
        </property>

        <!-- 第七种：设置空值 -->
        <property name="wife">
            <null></null>
        </property>

        <!--properties-->
        <property name="info">
            <props>
                <prop key="学号">20194074</prop>
                <prop key="性别">男</prop>
                <prop key="姓名">杨传伟</prop>
                <prop key="username">reliable</prop>
                <prop key="userpass">resetpass01</prop>
            </props>
        </property>
    </bean>
</beans>
```



